# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
import functions_framework
from urllib.parse import urlparse
import os

@functions_framework.http
def search_api(request):
    request_json = request.get_json(silent=True)
    
    # Database connection parameters
    db_config = {
        'host': os.environ.get('DB_HOST'),
        'user': os.environ.get('DB_USER'),
        'password': os.environ.get('DB_PASSWORD'),
        'database': os.environ.get('DB_NAME'),
        'port': int(os.environ.get('DB_PORT', 3306))
    }
    
    # Connect to database
    connection = pymysql.connect(**db_config)
    
    try:
        with connection.cursor() as cursor:
            # Build dynamic query from request parameters
            base_query = "SELECT * FROM products WHERE 1=1"
            params = []
            
            # Process each query parameter
            for key, value in request_json.items():
                if key == 'search':
                    # Search in multiple fields
                    base_query += " AND (name LIKE %s OR description LIKE %s)"
                    search_param = f"%{value}%"
                    params.extend([search_param, search_param])
                elif key == 'category':
                    base_query += " AND category = %s"
                    params.append(value)
                elif key == 'min_price':
                    base_query += " AND price >= %s"
                    params.append(float(value))
                elif key == 'max_price':
                    base_query += " AND price <= %s"
                    params.append(float(value))
                elif key == 'sort':
                    # Handle sorting
                    if value in ['name', 'price', 'created_at']:
                        base_query += f" ORDER BY {value}"
                elif key == 'limit':
                    base_query += " LIMIT %s"
                    params.append(int(value))
            
            # Execute query
            cursor.execute(base_query, params)
            results = cursor.fetchall()
            
            # Get column names
            columns = [desc[0] for desc in cursor.description]
            
            # Convert to list of dictionaries
            output = [dict(zip(columns, row)) for row in results]
            
            return {
                'status': 'success',
                'data': output,
                'count': len(output)
            }
            
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }
    finally:
        connection.close()